SELECT DISTINCT t.player_id, t.game_id
FROM (
    SELECT r1.player_id
    FROM (
        SELECT DISTINCT player_id FROM player_referrals WHERE referred_player_id IS NOT NULL
    ) r1
    INNER JOIN (
        SELECT DISTINCT player_id FROM player_rewards WHERE reward_date IS NOT NULL
    ) r2 ON r1.player_id = r2.player_id
) r
JOIN player_transactions t ON r.player_id = t.player_id;

SELECT email
FROM players
WHERE player_id = (SELECT player_id FROM player_transactions WHERE transaction_id = 0);

SELECT AVG(score) AS average_score
FROM sessions
WHERE game_id = 1 AND kit_id = 1 AND mode_id = 0;

SELECT player_id, username 
FROM players
WHERE player_id NOT IN (
  SELECT player_id 
  FROM sessions
);

SELECT 
  k.kit_name, 
  AVG(
    CAST(
      SUBSTR(s.duration, 1, INSTR(s.duration, ':') - 1) AS REAL
    ) + 
    CAST(
      SUBSTR(s.duration, INSTR(s.duration, ':') + 1) AS REAL
    ) / 60
  ) AS average_hours_played
FROM sessions s
JOIN kits k ON s.kit_id = k.kit_id
GROUP BY k.kit_name;
